import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import okhttp3.logging.HttpLoggingInterceptor
import java.util.concurrent.TimeUnit

class HttpClient {

    private val client: OkHttpClient

    init {
        val logging = HttpLoggingInterceptor()
        logging.setLevel(HttpLoggingInterceptor.Level.BODY)

        client = OkHttpClient.Builder()
            .addInterceptor(logging)
            .connectTimeout(10, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(15, TimeUnit.SECONDS)
            .build()
    }

    fun getRequest(url: String): Response? {
        val request = Request.Builder()
            .url(url)
            .build()

        return client.newCall(request).execute()
    }
}

// Usage example
fun main() {
    val httpClient = HttpClient()
    val response = httpClient.getRequest("http://192.168.1.1") // Local IoT device
    println(response?.body?.string())
    val cloudResponse = httpClient.getRequest("https://api.example.com") // Cloud API
    println(cloudResponse?.body?.string())
}